pattern_before:
// Branch-based free
if (buffer is at top of memory) {
    mstore(0x40, buffer) // restore free pointer
}

pattern_after:
// Branchless — writes to 0x40 or 0x00 based on condition
let n := mload(buffer)
mstore(
    shl(6, lt(iszero(n), eq(add(shl(5, add(1, n)), buffer), mload(0x40)))),
    buffer
)
